public void readEmployeeData(Connection conn, int empId) throws SQLException {
 String sql = "SELECT emp_id, name, salary, hire_date, is_active, profile_pic FROM employees WHERE emp_id = ?";

 try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
 pstmt.setInt(1, empId);

 try (ResultSet rs = pstmt.executeQuery()) {
 if (rs.next()) {
 // Integer - must check NULL manually
 int id = rs.getInt("emp_id");
 if (rs.wasNull()) { id = -1; }

 // String - handles NULL automatically
 String name = rs.getString("name");

 // BigDecimal - exact precision for money
 BigDecimal salary = rs.getBigDecimal("salary");

 // Date - returns java.sql.Date
 java.sql.Date hireDate = rs.getDate("hire_date");
 java.util.Date utilDate = (hireDate != null) ? new java.util.Date(hireDate.getTime()) : null;

 // Boolean - retrieves as boolean
 boolean active = rs.getBoolean("is_active");

 // BLOB - binary data
 byte[] profilePic = rs.getBytes("profile_pic");

 System.out.println("Employee: " + id + ", " + name + ", Salary: " + salary);
 System.out.println("Hired: " + utilDate + ", Active: " + active);
 }
 }
 }
}

public void insertDocument(Connection conn, String title, File documentFile, File imageFile) throws SQLException, IOException {
 String sql = "INSERT INTO documents(title, content, thumbnail) VALUES (?, ?, ?)";

 try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
 // Insert title as String
 pstmt.setString(1, title);

 // Insert CLOB using CharacterStream (for large text)
 try (FileReader reader = new FileReader(documentFile)) {
 pstmt.setCharacterStream(2, reader, documentFile.length());
 }

 // Insert BLOB using BinaryStream (for binary data)
 try (FileInputStream fis = new FileInputStream(imageFile)) {
 pstmt.setBinaryStream(3, fis, imageFile.length());
 }

 int rows = pstmt.executeUpdate();
 System.out.println("Inserted " + rows + " document(s)");
 }
}

// Alternative: Using setClob() and setBlob()
public void insertWithClobBlob(Connection conn, String text, byte[] data) throws SQLException {
 String sql = "INSERT INTO storage(text_data, binary_data) VALUES (?, ?)";

 try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
 // Using setClob for CLOB
 Clob textClob = conn.createClob();
 textClob.setString(1, text);
 pstmt.setClob(1, textClob);

 // Using setBlob for BLOB
 Blob binaryBlob = conn.createBlob();
 binaryBlob.setBytes(1, data);
 pstmt.setBlob(2, binaryBlob);

 pstmt.executeUpdate();
 }
}

public Map<String, Object> getRowAsMap(Connection conn, String table, int id) throws SQLException {
 Map<String, Object> row = new LinkedHashMap<>();

 String sql = "SELECT * FROM " + table + " WHERE id = ?";

 try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
 pstmt.setInt(1, id);

 try (ResultSet rs = pstmt.executeQuery()) {
 ResultSetMetaData metaData = rs.getMetaData();
 int columnCount = metaData.getColumnCount();

 if (rs.next()) {
 for (int i = 1; i <= columnCount; i++) {
 String columnName = metaData.getColumnName(i);
 int columnType = metaData.getColumnType(i);

 // Universal retrieval using getObject()
 Object value = rs.getObject(i);

 // Handle type-specific conversions
 if (value != null) {
 switch (columnType) {
 case Types.DATE:
 case Types.TIMESTAMP:
 // Convert sql.Date to java.util.Date
 value = new java.util.Date(((java.sql.Date) value).getTime());
 break;
 case Types.DECIMAL:
 case Types.NUMERIC:
 // Keep as BigDecimal for precision
 break;
 case Types.BLOB:
 // Convert BLOB to byte array
 Blob blob = (Blob) value;
 value = blob.getBytes(1, (int) blob.length());
 break;
 }
 }

 row.put(columnName, value);
 }
 }
 }
 }
 return row;
}
